TFT_eSPI& SplashScreen::render() {
  TFT_eSPI& tft = Screen::render();

  int16_t x = (tft.width() / 2) - (SplashScreen_WIDTH / 2);
  int16_t y = (tft.height() / 2) - (SplashScreen_HEIGHT / 2);

  tft.pushImage(x, y, SplashScreen_WIDTH, SplashScreen_HEIGHT, SplashScreenImage);

  return tft;
}

